def average_color(colors):
    if not colors:
        return (0, 0, 0)
    r_sum, g_sum, b_sum = 0, 0, 0
    for r, g, b in colors:
        r_sum += r
        g_sum += g
        b_sum += b
    avg_r = round(r_sum / len(colors))
    avg_g = round(g_sum / len(colors))
    avg_b = round(b_sum / len(colors))
    return (avg_r, avg_g, avg_b)

